solutions.javascript:
// Define a function to map host ports to container ports using Docker port mapping syntax
function solve(ports) {
    let result = ports.map(port => port.join(':')).join(',');
    return result;
}

solutions.python:
class Solution:
    def solve(self, ports):
        result = ','.join([f'{port[0]}:{port[1]}' for port in ports])
        return result
